import test from 'node:test';
import assert from 'node:assert/strict';

import { parseEntityTagList } from '../src/entity-tag-list.mjs';
import { evaluatePreconditions } from '../src/request-preconditions.mjs';

test('gateway-formatted catalog validators retain one revision token', () => {
  assert.deepEqual(
    parseEntityTagList('W/\"catalog,2026\", \"fallback\"'),
    ['W/\"catalog,2026\"', '\"fallback\"']
  );
});

test('a cache revalidation recognizes the deployed catalog revision', () => {
  assert.deepEqual(
    evaluatePreconditions({
      method: 'GET',
      currentTag: '\"catalog-7\"',
      ifNoneMatch: 'W/\"catalog-7\"'
    }),
    { status: 304, proceed: false }
  );
});

test('an update cannot rely on a non-authoritative catalog copy', () => {
  assert.deepEqual(
    evaluatePreconditions({
      method: 'PATCH',
      currentTag: '\"catalog-7\"',
      ifMatch: 'W/\"catalog-7\"'
    }),
    { status: 412, proceed: false }
  );
});
